// -------------------------
// Validation Configuration
export const settings = {
  formSelector: ".modal__form",
  inputSelector: ".modal__input",
  submitButtonSelector: ".modal__save-btn",
  inactiveButtonClass: "modal__save-btn_disabled",
  inputErrorClass: "modal__input_type_error",
  errorClass: "modal__error_visible",
};

// -------------------------
// Show input error
function showInputError(form, input, config) {
  const errorElement = form.querySelector(`#${input.id}-error`);
  if (!errorElement) return;

  input.classList.add(config.inputErrorClass);
  errorElement.textContent = input.validationMessage;
  errorElement.classList.add(config.errorClass);
}

// Hide input error
function hideInputError(form, input, config) {
  const errorElement = form.querySelector(`#${input.id}-error`);
  if (!errorElement) return;

  input.classList.remove(config.inputErrorClass);
  errorElement.textContent = "";
  errorElement.classList.remove(config.errorClass);
}

// -------------------------
// Check input validity
function checkInputValidity(form, input, config) {
  if (!input.validity.valid) {
    showInputError(form, input, config);
  } else {
    hideInputError(form, input, config);
  }
}

// -------------------------
// Check for invalid inputs
function hasInvalidInput(inputs) {
  if (!inputs || inputs.length === 0) return true;
  return inputs.some((input) => !input.validity.valid);
}

// Disable button
function disableButton(button, config) {
  if (!button) return;
  button.classList.add(config.inactiveButtonClass);
  button.disabled = true;
}

// Enable button
function enableButton(button, config) {
  if (!button) return;
  button.classList.remove(config.inactiveButtonClass);
  button.disabled = false;
}

// Toggle button state
function toggleButtonState(inputs, button, config) {
  if (hasInvalidInput(inputs)) {
    disableButton(button, config);
  } else {
    enableButton(button, config);
  }
}

// -------------------------
// Set listeners for one form
function setEventListeners(form, config) {
  if (!form) return;

  const inputs = Array.from(form.querySelectorAll(config.inputSelector));
  const button = form.querySelector(config.submitButtonSelector);

  if (!inputs.length || !button) return;

  toggleButtonState(inputs, button, config);

  inputs.forEach((input) => {
    input.addEventListener("input", () => {
      checkInputValidity(form, input, config);
      toggleButtonState(inputs, button, config);
    });
  });
}

// -------------------------
// Enable validation (MAIN)
export function enableValidation(config) {
  const forms = document.querySelectorAll(config.formSelector);

  forms.forEach((form) => {
    setEventListeners(form, config);
  });
}

// -------------------------
// Reset validation
export function resetValidation(form, config) {
  if (!form) return;

  const inputs = Array.from(form.querySelectorAll(config.inputSelector));
  const button = form.querySelector(config.submitButtonSelector);

  inputs.forEach((input) => {
    hideInputError(form, input, config);
  });

  toggleButtonState(inputs, button, config);
}

// -------------------------
// MODAL HANDLING (CLEAN VERSION)

// ESC handler (must be named to remove later)
function handleEscClose(evt) {
  if (evt.key === "Escape") {
    const openedModal = document.querySelector(".modal_is-opened");
    if (openedModal) closeModal(openedModal);
  }
}

// Open modal
export function openModal(modal) {
  if (!modal) return;

  modal.classList.add("modal_is-opened");
  document.addEventListener("keydown", handleEscClose);

  // Reset validation if form exists
  const form = modal.querySelector("form");
  if (form) {
    resetValidation(form, settings);
  }

  // Overlay click close
  modal.addEventListener("mousedown", (evt) => {
    if (evt.target === modal) {
      closeModal(modal);
    }
  });
}

// Close modal
export function closeModal(modal) {
  if (!modal) return;

  modal.classList.remove("modal_is-opened");
  document.removeEventListener("keydown", handleEscClose);
}
